commit 99128f360a7363a57903eccf3104f53859c6d868
Author: Matthias Jouanneaux <mjoux@nvidia.com>
Date:   Wed Dec 21 09:43:03 2022 -0800

    added tuple_element to jitsafe tuple header
---
 jitify.hpp | 12 ++++++++++++
 1 file changed, 12 insertions(+)

diff --git a/jitify.hpp b/jitify.hpp
index e8c7dd8..a837af9 100644
--- a/jitify.hpp
+++ b/jitify.hpp
@@ -2406,6 +2406,18 @@ static const char* jitsafe_header_tuple = R"(
     #if __cplusplus >= 201103L
     namespace std {
     template<class... Types > class tuple;
+
+    template< size_t I, class T >
+    struct tuple_element;
+    // recursive case
+    template< size_t I, class Head, class... Tail >
+    struct tuple_element<I, tuple<Head, Tail...>>
+        : tuple_element<I-1, tuple<Tail...>> { };
+    // base case
+    template< class Head, class... Tail >
+    struct tuple_element<0, tuple<Head, Tail...>> {
+      using type = Head;
+    };
     } // namespace std
     #endif
  )";

commit 6bc6e25e13300a8bc7520ed3bf977865201183b7
Author: Ben Barsdell <bbarsdell@nvidia.com>
Date:   Fri May 27 20:44:20 2022 +1000

    Add nvrtc_cli tool

    - This allows NVRTC to be driven via a nvrtc_cli executable that
      operates identically to nvcc (for the subset of functionality
      supported by NVRTC).
    - This is useful for testing, and we also plan to integrate it into
      the godbolt.org Compiler Explorer.
    - Includes a script for testing basic functionality of the tool.
---
 Makefile          |   4 +
 nvrtc_cli.cpp     | 586 ++++++++++++++++++++++++++++++++++++++++++++++++++++++
 nvrtc_cli_test.sh |  58 ++++++
 3 files changed, 648 insertions(+)

diff --git a/Makefile b/Makefile
index c683dcf..6b73d03 100644
--- a/Makefile
+++ b/Makefile
@@ -52,6 +52,10 @@ jitify_example: jitify_example.cpp $(HEADERS)
 stringify: stringify.cpp
 	$(CXX) -o $@ $< -O3 -Wall

+nvrtc_cli: nvrtc_cli.cpp
+	$(CXX) -o $@ $< -O3 -Wall -Wextra -std=c++11 -I$(CUDA_INC_DIR) -L$(CUDA_LIB_DIR) -lnvrtc
+	bash nvrtc_cli_test.sh
+
 get-deps:
 	sudo apt-get update
 	# CMake is needed to build gtest.
diff --git a/nvrtc_cli.cpp b/nvrtc_cli.cpp
new file mode 100644
index 0000000..4550c62
--- /dev/null
+++ b/nvrtc_cli.cpp
@@ -0,0 +1,586 @@
