commit f71e0429426b10f6b1137462ee03edf879bddeb0
Author: Ben Barsdell <bbarsdell@nvidia.com>
Date:   Sat Aug 1 11:47:39 2020 +1000

    Make serialization independent of host endianness

    - Changes the way integer values are serialized so that they are always
      written/read in little-endian order, independent of the host system.
    - On little-endian systems this does not change anything, but on other
      systems this is a binary-incompatible change and so the serialization
      version number has been incremented.
    - This will make serializations binary-compatible between systems of
      different endianness.
---
 jitify.hpp | 18 ++++++++++++++----
 1 file changed, 14 insertions(+), 4 deletions(-)

diff --git a/jitify.hpp b/jitify.hpp
index 29a81a1..8c42903 100644
--- a/jitify.hpp
+++ b/jitify.hpp
@@ -3657,16 +3657,26 @@ namespace detail {

 // This should be incremented whenever the serialization format changes in any
 // incompatible way.
-static constexpr const size_t kSerializationVersion = 1;
+static constexpr const size_t kSerializationVersion = 2;

 inline void serialize(std::ostream& stream, size_t u) {
   uint64_t u64 = u;
-  stream.write(reinterpret_cast<char*>(&u64), sizeof(u64));
+  char bytes[8];
+  for (int i = 0; i < (int)sizeof(bytes); ++i) {
+    // Convert to little-endian bytes.
+    bytes[i] = (unsigned char)(u64 >> (i * CHAR_BIT));
+  }
+  stream.write(bytes, sizeof(bytes));
 }

 inline bool deserialize(std::istream& stream, size_t* size) {
-  uint64_t u64;
-  stream.read(reinterpret_cast<char*>(&u64), sizeof(u64));
+  char bytes[8];
+  stream.read(bytes, sizeof(bytes));
+  uint64_t u64 = 0;
+  for (int i = 0; i < (int)sizeof(bytes); ++i) {
+    // Convert from little-endian bytes.
+    u64 |= uint64_t((unsigned char)(bytes[i])) << (i * CHAR_BIT);
+  }
   *size = u64;
   return stream.good();
 }

