+static const char* const reflection_program_source =
+    "reflection_program\n"
+    "struct Base { virtual ~Base() {} };\n"
+    "template <typename T>\n"
+    "struct Derived : public Base {};\n"
+    "template<typename T>\n"
+    "__global__ void type_kernel() {}\n"
