commit c3523766be23cf65692c5b10dd73d961636982d6
Author: Ben Barsdell <bbarsdell@nvidia.com>
Date:   Fri Feb 28 15:05:35 2020 +1100

    Use custom demangler for PTX variable names

    - PTX name mangling always follows the Itanium64 ABI scheme, even
      under MSVC. This means we can't use the platform-specific demangler
      for creating the map of __constant__/__device__ symbols.
    - The nvrtcGetLoweredName function would work except that it requires
      all names to have been added via nvrtcAddNameExpression _before_
      compilation, which is not feasible/convenient with our API.
    - This commit adds a simple custom demangler that supports nested
      namespace-scope variable names in the PTX (Itanium64) mangling
      format.
    - Only namespace-scope variable names need to be supported because
      __device__/__constant__ variables are only allowed at
      namespace-scope or function scope (if static), and the latter cannot
      be directly addressed from outside the function.
---
 jitify.hpp | 48 ++++++++++++++++++++++++++++++++++++------------
 1 file changed, 36 insertions(+), 12 deletions(-)

diff --git a/jitify.hpp b/jitify.hpp
index 7dd4269..7151518 100644
--- a/jitify.hpp
+++ b/jitify.hpp
@@ -962,6 +962,36 @@ inline std::string reflect_template() {

 namespace detail {

+// Demangles nested variable names using the PTX name mangling scheme
+// (which follows the Itanium64 ABI). E.g., _ZN1a3Foo2bcE -> a::Foo::bc.
+inline std::string demangle_ptx_variable_name(const char* name) {
+  std::stringstream ss;
+  const char* c = name;
+  if (*c++ != '_' || *c++ != 'Z') return name;  // Non-mangled name
+  if (*c++ != 'N') return "";  // Not a nested name, unsupported
+  while (true) {
+    // Parse identifier length.
+    int n = 0;
+    while (std::isdigit(*c)) {
+      n = n * 10 + (*c - '0');
+      c++;
+    }
+    if (!n) return "";  // Invalid or unsupported mangled name
+    // Parse identifier.
+    const char* c0 = c;
+    while (n-- && *c) c++;
+    if (!*c) return "";  // Mangled name is truncated
+    std::string id(c0, c);
+    // Identifiers starting with "_GLOBAL" are anonymous namespaces.
+    ss << (id.substr(0, 7) == "_GLOBAL" ? "(anonymous namespace)" : id);
+    // Nested name specifiers end with 'E'.
+    if (*c == 'E') break;
+    // There are more identifiers to come, add join token.
+    ss << "::";
+  }
+  return ss.str();
+}
+
 class CUDAKernel {
   std::vector<std::string> _link_files;
   std::vector<std::string> _link_paths;
