       size_t constant_end = line.find_last_of("[");
       std::string entry =
           line.substr(constant_start, constant_end - constant_start);
-
-#ifdef _MSC_VER  // interpret anything that doesn't begine ? as unmangled name
-      std::string key = (entry[0] != '?')
