@@ -2189,6 +2276,9 @@ inline nvrtcResult compile_kernel(std::string program_name,
     std::vector<char> vptx(ptxsize);
     CHECK_NVRTC(nvrtcGetPTX(nvrtc_program, vptx.data()));
